# reranker_server.py — FastAPI wrapper around sentence-transformers from fastapi import FastAPI from pydantic import BaseModel from sentence_transformers import CrossEncoder import torch
app = FastAPI() MODEL = CrossEncoder("BAAI/bge-reranker-v2-m3", device="cuda" if torch.cuda.is_available() else "cpu")
class RerankRequest(BaseModel): query: str documents: list[str] top_k: int = 10
@app.post("/rerank") def rerank(req: RerankRequest): pairs = [(req.query, doc) for doc in req.documents] scores = MODEL.predict(pairs).tolist() ranked = sorted( [{"index": i, "document": doc, "score": scores[i]} for i, doc in enumerate(req.documents)], key=lambda x: x["score"], reverse=True, ) return {"results": ranked[: req.top_k]}

section.prompt:
You are a document relevance expert. Given a query and a list of documents, score each document's relevance to the query.
## Instructions 1. Read the query carefully to understand the user's information need 2. For each document, assess: - Does it directly answer the query? - Does it contain relevant information? - How specific and accurate is the information? 3. Assign a relevance score from 0-10: - 0-2: Irrelevant - 3-4: Marginally relevant - 5-6: Somewhat relevant - 7-8: Relevant - 9-10: Highly relevant, directly answers query
## Query {query}
## Documents {documents_formatted}
## Output Format Return a JSON object: { "rankings": [ {"index": 0, "score": 8.5, "reasoning": "brief explanation"}, {"index": 2, "score": 7.0, "reasoning": "brief explanation"}, ... ] }
Return only the top {top_k} most relevant documents, sorted by score descending.

Rank these documents by relevance to the query. Consider all documents together and compare them.

Query: {query}

Documents:
[0] {doc_0}
[1] {doc_1}
[2] {doc_2}
...

Return ONLY a JSON object with the indices of the {top_k} most relevant documents in order from most to least relevant:

{"ranking": [index1, index2, ...]}

The first index is most relevant.

Compare these two documents for relevance to the query.

Query: {query}

Document A:
{doc_a}

Document B:
{doc_b}

Which document is MORE relevant to answering the query?

Return ONLY: "A" if Document A is more relevant, "B" if Document B is more relevant, or "EQUAL" if equally relevant.

You are a legal document relevance expert. Rank documents for a legal research query.
## Special Considerations - Prioritize binding authority over persuasive authority - Consider jurisdiction relevance - Weight recent cases higher for evolving areas of law - Distinguish between holdings and dicta
## Query {query}
## Jurisdiction (if specified) {jurisdiction}
## Documents {documents}
## Scoring Criteria - 10: Directly on point, binding authority, recent - 8-9: Highly relevant, may be persuasive authority - 6-7: Relevant legal principle, different jurisdiction - 4-5: Tangentially related - 1-3: Marginally relevant - 0: Irrelevant
Return JSON with rankings and legal reasoning.

