""" Jina AI Reranker API integration. Supports Jina Reranker v2 and v3 models. """ import httpx from typing import List, Dict, Any, Optional import os from dataclasses import dataclass
@dataclass class JinaConfig: api_key: str model: str = "jina-reranker-v2-base-multilingual" base_url: str = "https://api.jina.ai/v1/rerank" timeout: int = 30
class JinaReranker: """Jina AI reranker with async support."""
MODELS = { "v2-base": "jina-reranker-v2-base-multilingual", "v2-turbo": "jina-reranker-v2-turbo-multilingual", # Faster "v3": "jina-reranker-v3" # Latest, SOTA }
def __init__(self, config: Optional[JinaConfig] = None): self.config = config or JinaConfig( api_key=os.getenv("JINA_API_KEY") ) self.headers = { "Authorization": f"Bearer {self.config.api_key}", "Content-Type": "application/json" }
def rerank( self, query: str, documents: List[str], top_n: int = 5 ) -> List[Dict[str, Any]]: payload = { "model": self.config.model, "query": query, "documents": documents, "top_n": top_n }
with httpx.Client(timeout=self.config.timeout) as client: response = client.post( self.config.base_url, headers=self.headers, json=payload ) response.raise_for_status()
data = response.json()
results = [] for r in data.get("results", []): results.append({ "document": documents[r["index"]], "score": r["relevance_score"], "original_index": r["index"] })
return results
async def arerank( self, query: str, documents: List[str], top_n: int = 5 ) -> List[Dict[str, Any]]: payload = { "model": self.config.model, "query": query, "documents": documents, "top_n": top_n }
async with httpx.AsyncClient(timeout=self.config.timeout) as client: response = await client.post( self.config.base_url, headers=self.headers, json=payload ) response.raise_for_status()
data = response.json()
results = [] for r in data.get("results", []): results.append({ "document": documents[r["index"]], "score": r["relevance_score"], "original_index": r["index"] })
return results

""" Reranking integration with LlamaIndex. """ from llama_index.core import VectorStoreIndex, SimpleDirectoryReader from llama_index.core.postprocessor import SentenceTransformerRerank from llama_index.postprocessor.cohere_rerank import CohereRerank from llama_index.core.retrievers import VectorIndexRetriever from llama_index.core.query_engine import RetrieverQueryEngine import os
class LlamaIndexRerankingRAG: """RAG pipeline with reranking using LlamaIndex."""
def __init__( self, reranker_type: str = "sentence-transformer", # or "cohere" reranker_model: str = "BAAI/bge-reranker-v2-m3", initial_k: int = 20, final_k: int = 5 ): self.initial_k = initial_k self.final_k = final_k self.index = None
if reranker_type == "sentence-transformer": self.reranker = SentenceTransformerRerank( model=reranker_model, top_n=final_k ) elif reranker_type == "cohere": self.reranker = CohereRerank( api_key=os.getenv("COHERE_API_KEY"), top_n=final_k ) else: raise ValueError(f"Unknown reranker type: {reranker_type}")
def load_documents(self, directory: str): documents = SimpleDirectoryReader(directory).load_data() self.index = VectorStoreIndex.from_documents(documents)
def create_index_from_texts(self, texts: list[str]): from llama_index.core import Document documents = [Document(text=t) for t in texts] self.index = VectorStoreIndex.from_documents(documents)
def query(self, question: str) -> str: if self.index is None: raise ValueError("Index not initialized. Load documents first.")
retriever = VectorIndexRetriever( index=self.index, similarity_top_k=self.initial_k ) query_engine = RetrieverQueryEngine( retriever=retriever, node_postprocessors=[self.reranker] ) response = query_engine.query(question) return str(response)

"""
LLM-based reranking for complex reasoning queries.
Uses LLM to score relevance with explanations.
"""
from typing import List, Dict, Any, Optional
from openai import OpenAI
import json


class LLMReranker:
    """
    LLM-based reranker using GPT-4 or similar models.
    Best for complex queries requiring reasoning.
    """

    def __init__(
        self,
        model: str = "gpt-4o-mini",
        api_key: Optional[str] = None
    ):
        self.client = OpenAI(api_key=api_key)
        self.model = model

    def rerank(
        self,
        query: str,
        documents: List[str],
        top_k: int = 5,
        explain: bool = False
    ) -> List[Dict[str, Any]]:
        if not documents:
            return []

        docs_text = "\n".join([
            f"[{i}] {doc[:500]}"
            for i, doc in enumerate(documents)
        ])

        if explain:
            prompt = self._build_explain_prompt(query, docs_text, top_k)
        else:
            prompt = self._build_score_prompt(query, docs_text, top_k)

        response = self.client.chat.completions.create(
            model=self.model,
            messages=[
                {"role": "system", "content": "You are a document relevance expert."},
                {"role": "user", "content": prompt}
            ],
            temperature=0,
            response_format={"type": "json_object"}
        )

        result = json.loads(response.choices[0].message.content)

        rankings = result.get("rankings", [])
        output = []
        for r in rankings[:top_k]:
            idx = r["index"]
            output.append({
                "document": documents[idx],
                "score": r["score"],
                "original_index": idx,
                "explanation": r.get("explanation", "") if explain else None
            })

        return output

    def _build_score_prompt(self, query: str, docs_text: str, top_k: int) -> str:
        return f"""Rate the relevance of each document to the query on a scale of 0-10.

Query: {query}

Documents:
{docs_text}

Return a JSON object with this structure:
{{
  "rankings": [
    {{"index": 0, "score": 8.5}},
    {{"index": 1, "score": 3.2}},
    ...
  ]
}}

Sort by score descending. Include top {top_k} most relevant documents."""

    def _build_explain_prompt(self, query: str, docs_text: str, top_k: int) -> str:
        return f"""Rate the relevance of each document to the query on a scale of 0-10.
Explain why each document is or isn't relevant.

Query: {query}

Documents:
{docs_text}

Return a JSON object with this structure:
{{
  "rankings": [
    {{"index": 0, "score": 8.5, "explanation": "Directly answers the question about..."}},
    {{"index": 1, "score": 3.2, "explanation": "Mentions related topic but..."}},
    ...
  ]
}}

Sort by score descending. Include top {top_k} most relevant documents."""

"""
Optimized batch reranking for high-throughput scenarios.
"""
from typing import List, Dict, Any, Tuple
from concurrent.futures import ThreadPoolExecutor, as_completed
from sentence_transformers import CrossEncoder
import numpy as np
import time


class BatchOptimizedReranker:
    """Batch-optimized reranker with parallel processing."""

    def __init__(
        self,
        model_name: str = "cross-encoder/ms-marco-MiniLM-L-12-v2",
        batch_size: int = 32,
        max_workers: int = 4
    ):
        self.model = CrossEncoder(model_name)
        self.batch_size = batch_size
        self.max_workers = max_workers

    def rerank_single(
        self,
        query: str,
        documents: List[str],
        top_k: int = 5
    ) -> List[Dict[str, Any]]:
        pairs = [[query, doc] for doc in documents]

        all_scores = []
        for i in range(0, len(pairs), self.batch_size):
            batch = pairs[i:i + self.batch_size]
            scores = self.model.predict(batch)
            if scores.ndim == 0:
                scores = np.array([scores])
            all_scores.extend(scores.tolist())

        scores_array = np.array(all_scores)
        sorted_indices = np.argsort(scores_array)[::-1][:top_k]

        return [
            {
                "document": documents[i],
                "score": float(scores_array[i]),
                "original_index": i
            }
            for i in sorted_indices
        ]

    def rerank_batch(
        self,
        queries: List[str],
        document_lists: List[List[str]],
        top_k: int = 5
    ) -> List[List[Dict[str, Any]]]:
        results = [None] * len(queries)

        with ThreadPoolExecutor(max_workers=self.max_workers) as executor:
            futures = {
                executor.submit(self.rerank_single, q, docs, top_k): i
                for i, (q, docs) in enumerate(zip(queries, document_lists))
            }

            for future in as_completed(futures):
                idx = futures[future]
                try:
                    results[idx] = future.result()
                except Exception as e:
                    results[idx] = [{"error": str(e)}]

        return results


class CachedReranker:
    """Reranker with result caching for repeated queries."""

    def __init__(
        self,
        reranker,
        cache_size: int = 1000,
        ttl_seconds: int = 3600
    ):
        self.reranker = reranker
        self.cache = {}
        self.cache_timestamps = {}
        self.cache_size = cache_size
        self.ttl_seconds = ttl_seconds

    def _cache_key(self, query: str, documents: Tuple[str, ...], top_k: int) -> str:
        import hashlib
        doc_hash = hashlib.md5(str(documents).encode()).hexdigest()
        return f"{query}:{doc_hash}:{top_k}"

    def _evict_expired(self):
        current_time = time.time()
        expired = [
            key for key, ts in self.cache_timestamps.items()
            if current_time - ts > self.ttl_seconds
        ]
        for key in expired:
            del self.cache[key]
            del self.cache_timestamps[key]

    def _evict_oldest(self):
        while len(self.cache) >= self.cache_size:
            oldest_key = min(self.cache_timestamps, key=self.cache_timestamps.get)
            del self.cache[oldest_key]
            del self.cache_timestamps[oldest_key]

    def rerank(
        self,
        query: str,
        documents: List[str],
        top_k: int = 5
    ) -> List[Dict[str, Any]]:
        docs_tuple = tuple(documents)
        cache_key = self._cache_key(query, docs_tuple, top_k)

        if cache_key in self.cache:
            if time.time() - self.cache_timestamps[cache_key] < self.ttl_seconds:
                return self.cache[cache_key]

        self._evict_expired()
        self._evict_oldest()

        result = self.reranker.rerank(query, documents, top_k)

        self.cache[cache_key] = result
        self.cache_timestamps[cache_key] = time.time()

        return result

"""
Template: Basic two-stage retrieval pipeline with reranking.
Copy and customize for your use case.
"""
from typing import List, Dict, Any, Optional, Protocol
from dataclasses import dataclass, field
import logging

logger = logging.getLogger(__name__)


@dataclass
class RerankerConfig:
    model_type: str = "cross-encoder"  # cross-encoder, cohere, jina, llm
    model_name: str = "cross-encoder/ms-marco-MiniLM-L-12-v2"
    api_key: Optional[str] = None
    device: str = "cpu"
    max_length: int = 512
    batch_size: int = 32
    timeout: int = 30


@dataclass
class RetrievalConfig:
    initial_top_k: int = 50
    rerank_top_k: int = 5
    enable_reranking: bool = True
    fallback_on_error: bool = True
    cache_enabled: bool = True
    cache_ttl: int = 3600


class Retriever(Protocol):
    def retrieve(self, query: str, top_k: int) -> List[Dict[str, Any]]: ...


class Reranker(Protocol):
    def rerank(
        self,
        query: str,
        documents: List[str],
        top_k: int
    ) -> List[Dict[str, Any]]: ...


class RerankerFactory:
    """Factory for creating rerankers based on config."""

    @staticmethod
    def create(config: RerankerConfig) -> Reranker:
        if config.model_type == "cross-encoder":
            return CrossEncoderReranker(config)
        elif config.model_type == "cohere":
            return CohereReranker(config)
        elif config.model_type == "jina":
            return JinaReranker(config)
        elif config.model_type == "llm":
            return LLMReranker(config)
        else:
            raise ValueError(f"Unknown reranker type: {config.model_type}")


class RerankingPipeline:
    """Two-stage retrieval pipeline with reranking."""

    def __init__(
        self,
        retriever: Retriever,
        reranker_config: RerankerConfig,
        config: RetrievalConfig = None
    ):
        self.retriever = retriever
        self.config = config or RetrievalConfig()
        self.reranker = RerankerFactory.create(reranker_config)
        self._cache: Dict[str, Any] = {}

    def retrieve(
        self,
        query: str,
        filter: Optional[Dict] = None
    ) -> List[Dict[str, Any]]:
        try:
            if self.config.cache_enabled:
                cache_key = f"{query}:{filter}"
                if cache_key in self._cache:
                    return self._cache[cache_key]

            initial_results = self.retriever.retrieve(
                query=query,
                top_k=self.config.initial_top_k
            )

            if not initial_results:
                return []

            if self.config.enable_reranking:
                documents = [r.get("content", r.get("text", "")) for r in initial_results]

                reranked = self.reranker.rerank(
                    query=query,
                    documents=documents,
                    top_k=self.config.rerank_top_k
                )

                results = []
                for r in reranked:
                    original = initial_results[r["original_index"]].copy()
                    original["rerank_score"] = r["score"]
                    results.append(original)
            else:
                results = initial_results[:self.config.rerank_top_k]

            if self.config.cache_enabled:
                self._cache[cache_key] = results

            return results

        except Exception as e:
            logger.error(f"Reranking failed: {e}")
            if self.config.fallback_on_error:
                return initial_results[:self.config.rerank_top_k]
            raise

""" Template: FastAPI service for reranking. """ from fastapi import FastAPI, HTTPException from pydantic import BaseModel, Field from typing import List, Optional, Dict, Any import logging from contextlib import asynccontextmanager import time
logger = logging.getLogger(__name__)
class Document(BaseModel): text: str id: Optional[str] = None metadata: Optional[Dict[str, Any]] = None
class RerankRequest(BaseModel): query: str = Field(..., min_length=1, max_length=10000) documents: List[Document] = Field(..., min_items=1, max_items=1000) top_k: int = Field(default=5, ge=1, le=100) return_documents: bool = True
class RerankResult(BaseModel): index: int score: float document: Optional[Document] = None
class RerankResponse(BaseModel): results: List[RerankResult] model: str latency_ms: float
class HealthResponse(BaseModel): status: str model_loaded: bool version: str
class RerankingService: def __init__(self, model_name: str = "cross-encoder/ms-marco-MiniLM-L-12-v2"): self.model_name = model_name self.reranker = None self._load_model()
def _load_model(self): from sentence_transformers import CrossEncoder logger.info(f"Loading model: {self.model_name}") self.reranker = CrossEncoder(self.model_name) logger.info("Model loaded successfully")
def rerank( self, query: str, documents: List[str], top_k: int = 5 ) -> List[Dict[str, Any]]: import numpy as np pairs = [[query, doc] for doc in documents] scores = self.reranker.predict(pairs) sorted_indices = np.argsort(scores)[::-1][:top_k] return [ {"index": int(idx), "score": float(scores[idx])} for idx in sorted_indices ]
@property def is_ready(self) -> bool: return self.reranker is not None
service: Optional[RerankingService] = None
@asynccontextmanager async def lifespan(app: FastAPI): global service service = RerankingService() yield service = None
app = FastAPI( title="Reranking Service", description="Cross-encoder reranking API", version="1.0.0", lifespan=lifespan )
@app.get("/health", response_model=HealthResponse) async def health_check(): return HealthResponse( status="healthy" if service and service.is_ready else "unhealthy", model_loaded=service.is_ready if service else False, version="1.0.0" )
@app.post("/rerank", response_model=RerankResponse) async def rerank(request: RerankRequest): if not service or not service.is_ready: raise HTTPException(status_code=503, detail="Service not ready")
start_time = time.time()
try: documents = [doc.text for doc in request.documents] results = service.rerank( query=request.query, documents=documents, top_k=request.top_k )
response_results = [] for r in results: result = RerankResult( index=r["index"], score=r["score"], document=request.documents[r["index"]] if request.return_documents else None ) response_results.append(result)
latency_ms = (time.time() - start_time) * 1000
return RerankResponse( results=response_results, model=service.model_name, latency_ms=latency_ms )
except Exception as e: logger.error(f"Reranking failed: {e}") raise HTTPException(status_code=500, detail=str(e))

"""
Template: Quality evaluation for reranking.
"""
from typing import List, Dict, Tuple
import numpy as np
from dataclasses import dataclass


@dataclass
class EvaluationResult:
    ndcg_at_k: Dict[int, float]
    mrr: float
    precision_at_k: Dict[int, float]
    recall_at_k: Dict[int, float]
    map_score: float


class RerankingEvaluator:
    """Evaluate reranking quality."""

    def __init__(self, reranker):
        self.reranker = reranker

    def evaluate(
        self,
        queries: List[str],
        documents_per_query: List[List[str]],
        relevance_labels: List[List[int]],
        k_values: List[int] = [1, 3, 5, 10]
    ) -> EvaluationResult:
        ndcg_scores = {k: [] for k in k_values}
        mrr_scores = []
        precision_scores = {k: [] for k in k_values}
        recall_scores = {k: [] for k in k_values}
        ap_scores = []

        for query, docs, labels in zip(queries, documents_per_query, relevance_labels):
            results = self.reranker.rerank(query, docs, top_k=max(k_values))
            reranked_indices = [r["original_index"] for r in results]

            for k in k_values:
                ndcg_scores[k].append(self._ndcg_at_k(labels, reranked_indices, k))
                precision_scores[k].append(self._precision_at_k(labels, reranked_indices, k))
                recall_scores[k].append(self._recall_at_k(labels, reranked_indices, k))

            mrr_scores.append(self._mrr(labels, reranked_indices))
            ap_scores.append(self._average_precision(labels, reranked_indices))

        return EvaluationResult(
            ndcg_at_k={k: np.mean(scores) for k, scores in ndcg_scores.items()},
            mrr=np.mean(mrr_scores),
            precision_at_k={k: np.mean(scores) for k, scores in precision_scores.items()},
            recall_at_k={k: np.mean(scores) for k, scores in recall_scores.items()},
            map_score=np.mean(ap_scores)
        )

    def _ndcg_at_k(self, relevance: List[int], ranking: List[int], k: int) -> float:
        dcg = 0.0
        for i, idx in enumerate(ranking[:k]):
            rel = relevance[idx]
            dcg += (2 ** rel - 1) / np.log2(i + 2)
        sorted_rel = sorted(relevance, reverse=True)
        idcg = sum(
            (2 ** rel - 1) / np.log2(i + 2)
            for i, rel in enumerate(sorted_rel[:k])
        )
        return dcg / idcg if idcg > 0 else 0.0

    def _mrr(self, relevance: List[int], ranking: List[int]) -> float:
        for i, idx in enumerate(ranking):
            if relevance[idx] > 0:
                return 1.0 / (i + 1)
        return 0.0

    def _precision_at_k(self, relevance: List[int], ranking: List[int], k: int) -> float:
        relevant_in_top_k = sum(1 for idx in ranking[:k] if relevance[idx] > 0)
        return relevant_in_top_k / k

    def _recall_at_k(self, relevance: List[int], ranking: List[int], k: int) -> float:
        total_relevant = sum(1 for r in relevance if r > 0)
        if total_relevant == 0:
            return 0.0
        relevant_in_top_k = sum(1 for idx in ranking[:k] if relevance[idx] > 0)
        return relevant_in_top_k / total_relevant

    def _average_precision(self, relevance: List[int], ranking: List[int]) -> float:
        relevant_count = 0
        precision_sum = 0.0
        for i, idx in enumerate(ranking):
            if relevance[idx] > 0:
                relevant_count += 1
                precision_sum += relevant_count / (i + 1)
        total_relevant = sum(1 for r in relevance if r > 0)
        return precision_sum / total_relevant if total_relevant > 0 else 0.0

"""
Template: Configuration loader for reranking pipeline.
"""
import os
import yaml
from dataclasses import dataclass, field
from typing import Optional, Dict, Any
from pathlib import Path


@dataclass
class ModelConfig:
    name: str = "cross-encoder/ms-marco-MiniLM-L-12-v2"
    device: str = "cpu"
    max_length: int = 512
    batch_size: int = 32


@dataclass
class APIConfig:
    key: Optional[str] = None
    timeout: int = 30
    max_retries: int = 3


@dataclass
class RerankerTypeConfig:
    type: str = "cross-encoder"
    model: ModelConfig = field(default_factory=ModelConfig)
    api: APIConfig = field(default_factory=APIConfig)


@dataclass
class RetrievalTypeConfig:
    initial_top_k: int = 50
    rerank_top_k: int = 5
    enabled: bool = True
    fallback_on_error: bool = True


@dataclass
class CacheConfig:
    enabled: bool = True
    ttl_seconds: int = 3600
    max_size: int = 10000


@dataclass
class BatchConfig:
    max_batch_size: int = 100
    batch_timeout_ms: int = 50


@dataclass
class PerformanceConfig:
    cache: CacheConfig = field(default_factory=CacheConfig)
    batch: BatchConfig = field(default_factory=BatchConfig)
    max_concurrent_requests: int = 10


@dataclass
class MetricsConfig:
    enabled: bool = True
    prefix: str = "reranker"


@dataclass
class LoggingConfig:
    level: str = "INFO"
    format: str = "json"


@dataclass
class AlertsConfig:
    latency_p99_ms: int = 500
    error_rate_percent: float = 1.0


@dataclass
class MonitoringConfig:
    metrics: MetricsConfig = field(default_factory=MetricsConfig)
    logging: LoggingConfig = field(default_factory=LoggingConfig)
    alerts: AlertsConfig = field(default_factory=AlertsConfig)


@dataclass
class RerankingConfig:
    """Complete reranking configuration."""
    reranker: RerankerTypeConfig = field(default_factory=RerankerTypeConfig)
    retrieval: RetrievalTypeConfig = field(default_factory=RetrievalTypeConfig)
    performance: PerformanceConfig = field(default_factory=PerformanceConfig)
    monitoring: MonitoringConfig = field(default_factory=MonitoringConfig)

    @classmethod
    def from_yaml(cls, path: str) -> "RerankingConfig":
        """Load configuration from YAML file."""
        with open(path) as f:
            data = yaml.safe_load(f)

        # Expand environment variables
        data = cls._expand_env_vars(data)

        return cls._from_dict(data)

    @classmethod
    def _expand_env_vars(cls, data: Any) -> Any:
        """Recursively expand environment variables."""
        if isinstance(data, str):
            if data.startswith("${") and data.endswith("}"):
                env_var = data[2:-1]
                return os.environ.get(env_var, "")
            return data
        elif isinstance(data, dict):
            return {k: cls._expand_env_vars(v) for k, v in data.items()}
        elif isinstance(data, list):
            return [cls._expand_env_vars(item) for item in data]
        return data

    @classmethod
    def _from_dict(cls, data: Dict) -> "RerankingConfig":
        """Create config from dictionary."""
        reranker_data = data.get("reranker", {})
        retrieval_data = data.get("retrieval", {})
        performance_data = data.get("performance", {})
        monitoring_data = data.get("monitoring", {})

        return cls(
            reranker=RerankerTypeConfig(
                type=reranker_data.get("type", "cross-encoder"),
                model=ModelConfig(**reranker_data.get("model", {})),
                api=APIConfig(**reranker_data.get("api", {}))
            ),
            retrieval=RetrievalTypeConfig(**retrieval_data),
            performance=PerformanceConfig(
                cache=CacheConfig(**performance_data.get("cache", {})),
                batch=BatchConfig(**performance_data.get("batch", {})),
                max_concurrent_requests=performance_data.get("max_concurrent_requests", 10)
            ),
            monitoring=MonitoringConfig(
                metrics=MetricsConfig(**monitoring_data.get("metrics", {})),
                logging=LoggingConfig(**monitoring_data.get("logging", {})),
                alerts=AlertsConfig(**monitoring_data.get("alerts", {}))
            )
        )


# Usage
if __name__ == "__main__":
    # Load from file
    config = RerankingConfig.from_yaml("reranking-config.yaml")

    # Or create programmatically
    config = RerankingConfig(
        reranker=RerankerTypeConfig(
            type="cohere",
            api=APIConfig(key=os.getenv("COHERE_API_KEY"))
        ),
        retrieval=RetrievalTypeConfig(initial_top_k=100, rerank_top_k=10)
    )

    print(f"Reranker type: {config.reranker.type}")
    print(f"Initial top-k: {config.retrieval.initial_top_k}")

""" Template: Benchmark tests for reranking performance. """ import pytest import time import statistics from typing import List, Dict import json
class RerankingBenchmark: """Benchmark reranking performance."""
def __init__(self, reranker): self.reranker = reranker self.results: List[Dict] = []
def run_latency_benchmark( self, query: str, documents: List[str], iterations: int = 100, warmup: int = 10 ) -> Dict: """Measure reranking latency.""" # Warmup for _ in range(warmup): self.reranker.rerank(query, documents, top_k=5)
# Benchmark latencies = [] for _ in range(iterations): start = time.perf_counter() self.reranker.rerank(query, documents, top_k=5) latencies.append((time.perf_counter() - start) * 1000) # ms
result = { "iterations": iterations, "doc_count": len(documents), "p50_ms": statistics.median(latencies), "p90_ms": sorted(latencies)[int(iterations * 0.9)], "p99_ms": sorted(latencies)[int(iterations * 0.99)], "mean_ms": statistics.mean(latencies), "std_ms": statistics.stdev(latencies) }
self.results.append(result) return result
def run_throughput_benchmark( self, query: str, documents: List[str], duration_seconds: int = 10 ) -> Dict: """Measure reranking throughput.""" start = time.perf_counter() count = 0
while time.perf_counter() - start < duration_seconds: self.reranker.rerank(query, documents, top_k=5) count += 1
elapsed = time.perf_counter() - start
result = { "duration_seconds": elapsed, "total_requests": count, "requests_per_second": count / elapsed, "doc_count": len(documents) }
self.results.append(result) return result
def save_results(self, path: str): """Save benchmark results to file.""" with open(path, "w") as f: json.dump(self.results, f, indent=2)
